recipe_list_screen.content:
const recipes = [
    { title: "Spaghetti Carbonara", rating: 4, ingredients: ["spaghetti", "eggs", "bacon"], instructions: "Boil water, cook pasta, fry bacon, mix eggs and cheese, toss with pasta." },
    { title: "Caesar Salad", rating: 5, ingredients: ["romaine lettuce", "croutons", "parmesan"], instructions: "Toss lettuce with croutons and parmesan, drizzle with Caesar dressing." }
];

const recipeList = document.getElementById('recipe-list');
const searchBar = document.getElementById('search-bar');

function renderRecipes(recipes) {
    recipeList.innerHTML = '';
    recipes.forEach(recipe => {
        const card = document.createElement('div');
        card.className = 'recipe-card';
        card.innerHTML = `
            <div class="recipe-title">${recipe.title}</div>
            <div class="recipe-rating">${recipe.rating} stars</div>
            <a href="#" class="read-more">Read More</a>
        `;
        recipeList.appendChild(card);
    });
}

searchBar.addEventListener('input', () => {
    const searchTerm = searchBar.value.toLowerCase();
    const filteredRecipes = recipes.filter(recipe => recipe.title.toLowerCase().includes(searchTerm));
    renderRecipes(filteredRecipes);
});

renderRecipes(recipes);

